        Assert.Contains(references, reference =>
            reference.SymbolName == "setup"
            && reference.ReferenceKind == "call"
            && reference.ContainerName == "run");
        Assert.Contains(references, reference =>
            reference.SymbolName == "cleanup"
            && reference.ReferenceKind == "call"
            && reference.ContainerName == "run");
    }

