                    self::rebuild();
                    static::rebuild();
                }
            }

            enum Priority: int {
                case Low = 1;
            }

            function inspect(): void {
                Config::rebuild();
                Config::VERSION;
                \App\Models\Config::class;
                \App\Models\Config::rebuild();
                Priority::Low;
            }
            ?>
            """;

