        // 残し、`/.../` が regex literal として解釈されること。division 扱いされると
        // バッククォートを template literal 開始と誤認して後続コードを潰す。
        const string content = "function main(value) {\n"
            + "    if (value) { }\n"
            + "    /`/.test(value);\n"
