    public void Extract_JsTemplateHoleSwitchDefaultBlockThenRegex_PreservesFollowingCall()
    {
        // Same regression for `default: { }` inside a template hole.
        // テンプレートホール内の `default: { }` についても同じ回帰。
        const string content = "function caller(value) {\n"
            + "    const s = `${(() => { switch (value) { default: { } /`/.test(value); runTask(); return 1; } })()}`;\n"
            + "    realCall();\n"
            + "}\n"
            + "function runTask() {}\n"
            + "function realCall() {}\n";

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "runTask" && r.ContainerName == "caller");
        Assert.Contains(references, r => r.SymbolName == "realCall" && r.ContainerName == "caller");
    }

    [Fact]
    public void Extract_JsTemplateLiteralArgumentInIfCondition_PreservesFollowingCall()
    {
        // Regression: the lex state captured just before a template literal must be
        // restored when the closing backtick is reached, or the statement-head `(`
        // of `if (` / `while (` / etc. is lost and the next `/` after `)` falls to
        // division. That then reads the backtick inside `/regex/` as a phantom
        // template opener and eats the real `realCall()` edge after the expression.
        // 回帰: テンプレートリテラル開始時に退避した lex state を閉じ backtick で
        // 復元しないと `if (` / `while (` などの statement-head `(` が失われ、
        // `)` の直後の `/` が division に落ちる。結果 `/regex/` 内の backtick が
        // phantom テンプレート開始と誤認され、後続の `realCall()` まで潰れる。
        const string content = "function caller(value) {\n"
            + "    if (`${value}`) /`/.test(value);\n"
            + "    realCall();\n"
            + "}\n"
            + "function realCall() {}\n";

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "realCall" && r.ContainerName == "caller");
    }

    [Fact]
    public void Extract_JsTemplateHoleNestedTemplateInIfCondition_PreservesFollowingCall()
    {
        // Same regression, but the problematic template appears inside an outer
        // template hole. The nested template's closing backtick must restore the
        // hole's lex state so the `)` after it is recognized as closing the `if`
        // condition paren and the subsequent `/regex/` parses as a regex literal.
        // 同じ回帰の入れ子版: 外側テンプレートホール内で `if (\`${x}\`) /.../` が
        // 使われるケース。内側テンプレート閉じで hole の lex state を復元しないと
        // `)` の後ろの `/` が division に落ち、`runTask` まで潰れる。
        const string content = "function caller(value) {\n"
            + "    const s = `${(() => { if (`${value}`) /`/.test(value); runTask(); return 1; })()}`;\n"
            + "    realCall();\n"
            + "}\n"
            + "function runTask() {}\n"
            + "function realCall() {}\n";

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "runTask" && r.ContainerName == "caller");
        Assert.Contains(references, r => r.SymbolName == "realCall" && r.ContainerName == "caller");
    }

    [Fact]
    public void Extract_JsOptionalChainingCall_CapturesCallReference()
    {
        // issue #294: `callback?.()` is an optional chaining call; the `?.` sits between the
        // identifier and the argument-list `(`, so the old CallRegex never reached the `(` and
        // silently dropped the `callback` call reference. Covers bare and argumented forms
        // plus a chained `obj?.handler?.()` where the captured identifier itself is only
        // reached by the call regex once `(?:\?\.)?` is in place.
        // issue #294: `callback?.()` は optional chaining 呼び出し。識別子と `(` の間に `?.` が入るため、
        // 旧 CallRegex では末尾 `(` まで到達できず `callback` への call 参照が欠落していた。
        // 引数なし・引数あり・プロパティチェーン末端で optional call される `obj?.handler?.()` の 3 形を検証する
        // （`handler` は `(?:\?\.)?` 追加後にだけ CallRegex にマッチする形）。
        const string content = """
            function caller(callback, onSuccess, obj) {
                callback?.();
                onSuccess?.(data);
                obj?.handler?.();
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "callback" && r.ReferenceKind == "call" && r.ContainerName == "caller");
        Assert.Contains(references, r =>
            r.SymbolName == "onSuccess" && r.ReferenceKind == "call" && r.ContainerName == "caller");
        Assert.Contains(references, r =>
            r.SymbolName == "handler" && r.ReferenceKind == "call" && r.ContainerName == "caller");
    }

    [Fact]
    public void Extract_TsOptionalChainingCallWithTypeArgs_CapturesCallReference()
    {
        // issue #294 follow-up: TypeScript allows type arguments after `?.` in
        // `callback?.<T>(...)`. The regex must keep matching when the optional chaining
        // is followed by a generic argument list before `(`.
        // issue #294 補足: TypeScript では optional chaining の直後に型引数が続く
        // `callback?.<T>(...)` が許容される。optional chaining と generic 引数が連続しても
        // regex が call 参照を取り逃がさないことを検証する。
        const string content = """
            function caller(callback: (<T>(value: T) => void) | undefined) {
                callback?.<number>(42);
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "typescript", content);
        var references = ReferenceExtractor.Extract(1, "typescript", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "callback" && r.ReferenceKind == "call" && r.ContainerName == "caller");
    }

    [Fact]
    public void Extract_JsNoParenConstructor_CapturesInstantiateReference()
    {
        // issue #295: JavaScript allows zero-arg constructor calls without `()`
        // (`new Foo;`, `new Date;`, `new Demo.Provider;`, `cond ? new Demo.Helper : other`). The generic CallRegex only
        // sees names that reach `(`, so these forms previously vanished from the
        // reference table and downstream graph queries under-counted instantiations.
        // issue #295: JavaScript では引数なしコンストラクタ呼び出しで `()` を省略できる
        // (`new Foo;`, `new Date;`, `new Demo.Provider;`, `cond ? new Demo.Helper : other`)。従来の汎用 CallRegex は
        // `(` まで届く名前しか拾えないため、これらの instantiate が参照テーブルから欠落していた。
        const string content = """
            class Foo {}

            function run(Demo) {
                const a = new Foo;
                const b = new Date;
                const c = new Demo.Provider;
                const d = ready ? new Demo.Helper : c;
                return [a, b, c, d];
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "Foo" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
        Assert.Contains(references, r =>
            r.SymbolName == "Date" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
        Assert.Contains(references, r =>
            r.SymbolName == "Provider" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
        Assert.Contains(references, r =>
            r.SymbolName == "Helper" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
    }

    [Fact]
    public void Extract_TsNoParenConstructorWithTypeArgs_CapturesInstantiateReference()
    {
        // issue #295 follow-up: TypeScript keeps the same no-paren `new` form even when
        // a single generic argument list is present (`new Box<number>;`). The dedicated
        // JS/TS path must keep accepting the one-level `<...>` segment already supported
        // by the shared `CallRegex` / initializer regex family.
        // issue #295 補足: TypeScript では generic 引数付きでも no-paren `new`
        // (`new Box<number>;`) が現れる。専用 JS/TS 経路でも既存 regex 群と同じ
        // 1 段の `<...>` を受け入れて instantiate を落とさないことを確認する。
        const string content = """
            class Box<T> {}

            function run() {
                const value = new Box<number>;
                return value;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "typescript", content);
        var references = ReferenceExtractor.Extract(1, "typescript", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "Box" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
    }

    [Fact]
    public void Extract_JsNoParenConstructor_NextLineMemberContinuation_DoesNotEmitPhantomInstantiate()
    {
        // issue #859: the no-paren `new` fix for #295 must stay suppressed when the next
        // physical line continues the expression (`new Foo\n.bar()`), otherwise the graph
        // regresses by inventing a standalone `instantiate Foo` edge.
        // issue #859: #295 の no-paren `new` 修正は、次の物理行で式が継続する
        // (`new Foo\n.bar()`) 場合に suppress を維持しないと phantom `instantiate Foo`
        // を発生させてグラフを壊してしまう。
        const string content = """
            class Foo {
                bar() {
                    return 1;
                }
            }

            function run() {
                const value = new Foo
                    .bar();
                return value;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.DoesNotContain(references, r =>
            r.SymbolName == "Foo" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
        Assert.Contains(references, r =>
            r.SymbolName == "bar" && r.ReferenceKind == "call" && r.ContainerName == "run");
    }

    [Fact]
    public void Extract_JsNoParenConstructor_NextLineIndexContinuation_DoesNotEmitPhantomInstantiate()
    {
        // issue #859: bracket continuations such as `new Foo\n[0]` are still the same
        // expression and must not be promoted into a terminated no-paren constructor site.
        // issue #859: `new Foo\n[0]` のような添字継続も同じ式の続きなので、
        // 終端済み no-paren constructor として昇格させてはいけない。
        const string content = """
            class Foo {
                constructor() {
                    this[0] = 1;
                }
            }

            function run() {
                const value = new Foo
                    [0];
                return value;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.DoesNotContain(references, r =>
            r.SymbolName == "Foo" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
    }

    [Fact]
    public void Extract_JsNoParenConstructor_NextLineCallContinuation_DoesNotEmitPhantomInstantiate()
    {
        // issue #859: the dedicated no-paren path must also stay off when the next line
        // begins with `(`, because `new Foo\n(arg)` is a continued call expression rather
        // than the statement-like zero-argument form fixed in #295.
        // issue #859: 次行が `(` で始まる場合も専用 no-paren 経路は抑止されるべきで、
        // `new Foo\n(arg)` は #295 が対象にした statement-like な zero-arg 形式ではない。
        const string content = """
            function Foo(value) {
                return value;
            }

            function run(arg) {
                const value = new Foo
                    (arg);
                return value;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "javascript", content);
        var references = ReferenceExtractor.Extract(1, "javascript", content, symbols);

        Assert.DoesNotContain(references, r =>
            r.SymbolName == "Foo" && r.ReferenceKind == "instantiate" && r.ContainerName == "run");
    }

    [Fact]
    public void Extract_CsharpNameofTypeofDefault_CapturesArgumentAsTypeReference()
    {
        // issue #253: nameof/typeof/sizeof/default arguments are first-class compile-time
        // references; previously CallRegex dropped them because the argument has no `(`.
        // issue #253: nameof/typeof/sizeof/default の引数はコンパイル時参照。従来は
        // 末尾に `(` が無いため CallRegex で取り逃がしていた。
        const string content = """
            namespace Demo;

            public class Target
            {
                public int Alpha() => 1;
                public static int Beta() => 2;
            }

            public class Caller
            {
                public void Work()
                {
                    var n1 = nameof(Target.Alpha);
                    var n2 = nameof(Target);
                    var n3 = nameof(Beta);
                    var tp = typeof(Target);
                    Target? def = default(Target);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        var targetRefs = references.Where(r => r.SymbolName == "Target" && r.ReferenceKind == "type_reference").ToList();
        Assert.True(targetRefs.Count >= 4); // #256 also adds the local declaration type `Target? def`
        Assert.All(targetRefs, r => Assert.Equal("Work", r.ContainerName));

        Assert.Contains(references, r => r.SymbolName == "Alpha" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Beta" && r.ReferenceKind == "type_reference");

        // Keyword itself must never be emitted as a reference.
        // キーワード自体は参照として出力されない。
        Assert.DoesNotContain(references, r => r.SymbolName == "nameof");
        Assert.DoesNotContain(references, r => r.SymbolName == "typeof");
        Assert.DoesNotContain(references, r => r.SymbolName == "default");
    }

    [Fact]
    public void Extract_CsharpTypeof_HandlesGenericAndArrayArguments()
    {
        // typeof(List<Payload>) should capture both `List` and the nested generic argument.
        // C# built-in aliases inside generic arguments still must never appear as rows.
        // typeof(List<Payload>) は `List` と nested generic argument の両方を拾う。
        // generic 引数内の C# built-in alias は引き続きスキップする。
        const string content = """
            using System.Collections.Generic;

            public class Payload {}

            public class Caller
            {
                public void Work()
                {
                    var t1 = typeof(List<Payload>);
                    var t2 = typeof(System.Collections.Generic.Dictionary<string, Payload[]>);
                    var t3 = typeof(Dictionary<string, List<Payload>>);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "List" && r.ReferenceKind == "type_reference");
        Assert.True(references.Count(r => r.SymbolName == "Payload" && r.ReferenceKind == "type_reference") >= 3);
        // For dotted args, each segment gets its own row — preserves rename safety.
        // ドット付き引数は segment ごとに行を出す — rename 追跡のため。
        Assert.Contains(references, r => r.SymbolName == "System" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Collections" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Generic" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Dictionary" && r.ReferenceKind == "type_reference");

        // C# built-in aliases inside generic arguments must not surface as type_reference rows.
        // C# の built-in alias は type_reference としてインデックスしない。
        Assert.DoesNotContain(references, r => r.ReferenceKind == "type_reference" && (r.SymbolName == "int" || r.SymbolName == "string"));
    }

    [Fact]
    public void Extract_CsharpNameof_CapturesTrailingMemberAfterGenericMidPath()
    {
        // issue #253 review: `nameof(List<int>.Count)` must emit both `List` AND `Count`;
        // regex-only extraction stopped at `<`, dropping the actual member name that the user
        // is navigating to. The lexer skips generic `<...>` and resumes scanning at `.Count`.
        // issue #253 レビュー: `nameof(List<int>.Count)` は `List` と `Count` を両方拾う必要あり。
        const string content = """
            using System.Collections.Generic;

            public class Caller
            {
                public void Work()
                {
                    var n = nameof(List<int>.Count);
                    var n2 = nameof(System.Collections.Generic.Dictionary<string, int>.KeyCollection);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "List" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Count" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Dictionary" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "KeyCollection" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpNameof_SkipsGlobalAliasQualifier()
    {
        // issue #253 review: `nameof(global::System.String)` — `global` is a namespace alias
        // qualifier and should NOT be captured; `System` is a built-in alias and should be
        // skipped; only real user-indexed path segments remain (none in this example).
        // Before the fix, only the bogus `global` token was emitted.
        // issue #253 レビュー: `global::` のエイリアス修飾子は捕捉しない。
        const string content = """
            public class Caller
            {
                public void Work()
                {
                    var n = nameof(global::System.String);
                    var n2 = nameof(MyAlias::Some.Type);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.DoesNotContain(references, r => r.SymbolName == "global" && r.ReferenceKind == "type_reference");
        Assert.DoesNotContain(references, r => r.SymbolName == "MyAlias" && r.ReferenceKind == "type_reference");
        // BCL type names (`String`, capital) are real types and must surface; only lowercase
        // alias keywords (`string`) are filtered.
        // BCL 型名（`String`）は実型なので捕捉し、lowercase の alias だけを除外する。
        Assert.Contains(references, r => r.SymbolName == "System" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "String" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Some" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Type" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpTypeof_SkipsBuiltInAliasArguments()
    {
        // issue #253 review: `typeof(int)`, `sizeof(int)`, `typeof(string)` etc. resolve to
        // BCL primitives and should NOT pollute `references` / `inspect`. The ignore set
        // mirrors the Java primitive skip for `T.class`.
        // issue #253 レビュー: C# built-in alias は type_reference として索引しない。
        const string content = """
            public class Caller
            {
                public void Work()
                {
                    var t1 = typeof(int);
                    var t2 = typeof(string);
                    var t3 = typeof(object);
                    var s = sizeof(int);
                    var v = typeof(void);
                    var d = typeof(dynamic);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.DoesNotContain(references, r => r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpTypeKeyword_CapturesTupleElementsAcrossInnerParens()
    {
        // issue #253 review #2: `typeof((Foo, Bar))` / `default((Foo, Bar))` are tuple-typed
        // arguments where the indexed identifiers only exist inside inner parentheses. The old
        // lexer treated `(` as "skip balanced body", silently dropping Foo and Bar. The fixed
        // lexer tracks paren depth instead, so tuple element segments surface normally while
        // outer `)` still terminates the scan.
        // issue #253 レビュー #2: `typeof((Foo, Bar))` / `default((Foo, Bar))` のタプル型引数は、
        // 識別子が内側括弧の中にしか存在しない。旧 lexer は `(` を SkipBalanced で飛ばしていたため
        // Foo / Bar が silent に落ちていた。括弧深さ追跡に変えたことで tuple 要素も拾えるようになる。
        const string content = """
            public class Foo {}
            public class Bar {}
            public class Caller
            {
                public void Work()
                {
                    var t = typeof((Foo, Bar));
                    var d = default((Foo, Bar));
                    var n = typeof((Foo, Bar)[]);
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "Foo" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Bar" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpDefaultWithoutParens_IsNotCapturedAsTypeReference()
    {
        // `default;` alone (no parens) is a value expression, not a type reference.
        // The regex requires `default\s*\(...\)`, so bare `default` produces nothing.
        // `default;` 単体は値式であり型参照ではない。正規表現は `(` を必須にしている。
        const string content = """
            public class Caller
            {
                public int Work()
                {
                    return default;
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.DoesNotContain(references, r => r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_JavaDotClass_CapturesTypeChainAsTypeReference()
    {
        // issue #253: Java's `T.class` / `T[].class` are compile-time type literals that rename
        // tools already treat as references; primitive types are skipped.
        // issue #253: Java の `T.class` はコンパイル時型リテラル。プリミティブは除外する。
        const string content = """
            package demo;

            public class Target {
                public int alpha() { return 1; }
            }

            public class Caller {
                public void work() {
                    Class<?> t1 = Target.class;
                    Class<?> t2 = Target[].class;
                    Class<?> t3 = int.class;
                    Class<?> t4 = demo.Target.class;
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        // Plain `Target.class` + `Target[].class` + segment from `demo.Target.class`.
        // `demo.Target.class` の Target + 素の Target.class + Target[].class = 3 箇所。
        var targetRefs = references.Where(r => r.SymbolName == "Target" && r.ReferenceKind == "type_reference").ToList();
        Assert.Equal(3, targetRefs.Count);

        Assert.Contains(references, r => r.SymbolName == "demo" && r.ReferenceKind == "type_reference");
        // Java primitive type must be skipped / Java プリミティブ型は除外。
        Assert.DoesNotContain(references, r => r.SymbolName == "int" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_JavaDocLinks_CaptureTypeReferences()
    {
        const string content = """
            package demo;

            class User {
                void save() {}
            }

            class Helper {}
            class Hidden {}

            class Service {
                /**
                 * Uses {@link User#save()} and {@linkplain java.util.List<User>}.
                 * @see Helper
                 * @see <a href="https://example.invalid">external</a>
                 */
                void run() {}

                void other() {
                    /** {@link Hidden} */
                    int local = 0;
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "User" && r.ReferenceKind == "type_reference" && r.ContainerName == "run");
        Assert.Contains(references, r => r.SymbolName == "save" && r.ReferenceKind == "type_reference" && r.ContainerName == "run");
        Assert.Contains(references, r => r.SymbolName == "List" && r.ReferenceKind == "type_reference" && r.ContainerName == "run");
        Assert.Contains(references, r => r.SymbolName == "Helper" && r.ReferenceKind == "type_reference" && r.ContainerName == "run");
        Assert.DoesNotContain(references, r => r.SymbolName == "href" && r.ReferenceKind == "type_reference");
        Assert.DoesNotContain(references, r => r.SymbolName == "Hidden" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpTypePositions_CaptureTypeReferences()
    {
        // issue #256: base lists, declaration types, generic constraints, type tests,
        // and XML-doc crefs must all surface as `type_reference` edges.
        // issue #256: 継承リスト、宣言型、generic 制約、型テスト、XML doc cref を
        // `type_reference` として拾う必要がある。
        const string content = """
            using System.Collections.Generic;

            namespace Probe;

            public interface ILogger { void Log(string msg); }
            public class Base { public virtual void Do() {} }

            public class Derived : Base, ILogger
            {
                private ILogger _logger;
                public Base Parent { get; set; }

                public Derived(ILogger logger, Base parent)
                {
                    _logger = logger;
                    Parent  = parent;
                }

                public List<ILogger> GetAll() => new();

                public void Inspect(object o)
                {
                    if (o is Base b) { }
                    switch (o)
                    {
                        case ILogger l: break;
                        case Base b2:   break;
                    }
                    Base cast = o as Base;
                }

                public T Find<T>() where T : ILogger, new() => new T();

                /// <summary>
                /// References <see cref="Base.Do"/> and <seealso cref="ILogger.Log"/>.
                /// </summary>
                public void WithDocs() {}
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.True(references.Count(r => r.SymbolName == "Base" && r.ReferenceKind == "type_reference") >= 7);
        Assert.True(references.Count(r => r.SymbolName == "ILogger" && r.ReferenceKind == "type_reference") >= 6);
        Assert.Contains(references, r => r.SymbolName == "List" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Do" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Log" && r.ReferenceKind == "type_reference");
    }

    [Fact]
