    [Fact]
    public void Extract_CsharpShortAndTStyleTypeNames_CaptureTypeReferences()
    {
        // Regression for issue #644: real type names like `X` and `TResult` must not be
        // dropped just because they resemble generic parameter spellings.
        // issue #644 回帰: `X` や `TResult` のような実在型名を、generic parameter に似ている
        // という理由だけで落としてはならない。
        const string content = """
            class X {}
            class TResult {}

            class Demo
            {
                X field;
                X Make(X value)
                {
                    X local = new X();
                    return local;
                }

                TResult Use(TResult value) => value;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.True(references.Count(r => r.SymbolName == "X" && r.ReferenceKind == "type_reference") >= 3);
        Assert.True(references.Count(r => r.SymbolName == "TResult" && r.ReferenceKind == "type_reference") >= 2);
    }

    [Fact]
    public void Extract_JavaGenericBounds_CaptureRealBoundsAndIgnoreParameterNames()
    {
        // Regression for issue #642: Java generic type-parameter bounds should emit the real
        // bound types, including nested generic bounds, while keeping the parameter names out
        // of the type_reference graph.
        // issue #642 回帰: Java の generic type-parameter bounds は、ネストした generic bound
        // を含めて実際の bound 型を拾いつつ、parameter 名は type_reference graph に出さないこと。
        const string content = """
            class Root {}
            interface Bound {}
            class Wrapper<T> {}

            class Demo<T extends Root & Bound> {
                <U extends Wrapper<Root>> U run(U value) {
                    return value;
                }
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.Contains(references, r => r.SymbolName == "Root" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Bound" && r.ReferenceKind == "type_reference");
        Assert.Contains(references, r => r.SymbolName == "Wrapper" && r.ReferenceKind == "type_reference");
        Assert.True(references.Count(r => r.SymbolName == "Root" && r.ReferenceKind == "type_reference") >= 2);
    }

    [Fact]
    public void Extract_TypePositionDetection_DoesNotTreatCallReceiversAsReturnTypes()
    {
        const string csharp = """
            class Demo
            {
                Service service;

                void Run()
                {
                    Console.WriteLine("x");
                    service.DoWork(1);
                }
            }

            class Service
            {
                void DoWork(int x) {}
            }
            """;

        var csharpSymbols = SymbolExtractor.Extract(1, "csharp", csharp);
        var csharpReferences = ReferenceExtractor.Extract(1, "csharp", csharp, csharpSymbols);

        Assert.DoesNotContain(csharpReferences, r => r.SymbolName == "Console" && r.ReferenceKind == "type_reference");
        Assert.DoesNotContain(csharpReferences, r => r.SymbolName == "service" && r.ReferenceKind == "type_reference");
        Assert.Contains(csharpReferences, r => r.SymbolName == "Service" && r.ReferenceKind == "type_reference");

        const string java = """
            class Demo {
                Logger logger;

                void run() {
                    logger.info("x");
                    Util.work(1);
                }
            }

            class Logger { void info(String s) {} }
            class Util { static void work(int x) {} }
            """;

        var javaSymbols = SymbolExtractor.Extract(1, "java", java);
        var javaReferences = ReferenceExtractor.Extract(1, "java", java, javaSymbols);

        Assert.DoesNotContain(javaReferences, r => r.SymbolName == "logger" && r.ReferenceKind == "type_reference");
        Assert.DoesNotContain(javaReferences, r => r.SymbolName == "Util" && r.ReferenceKind == "type_reference" && r.Line == 5);
        Assert.Contains(javaReferences, r => r.SymbolName == "Logger" && r.ReferenceKind == "type_reference");
    }

    [Fact]
    public void Extract_CsharpDocCref_UsesDocumentedMemberAsContainer()
    {
        const string content = """
            class Base { public void Do() {} }
            interface ILogger { void Log(); }
            class Derived {
                /// <summary>
                /// References <see cref="Base.Do"/> and <seealso cref="ILogger.Log"/>.
                /// </summary>
                public void WithDocs() {}
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols)
            .Where(r => r.Line == 5 && r.ReferenceKind == "type_reference")
            .ToList();

        Assert.Equal(4, references.Count);
        Assert.All(references, r => Assert.Equal("WithDocs", r.ContainerName));
        Assert.Contains(references, r => r.SymbolName == "Base");
        Assert.Contains(references, r => r.SymbolName == "Do");
        Assert.Contains(references, r => r.SymbolName == "ILogger");
        Assert.Contains(references, r => r.SymbolName == "Log");
    }

