    [Fact]
    public void Extract_Php_SingleQuotedDefaultArgument_PreservesFunctionBodyRange()
    {
        // Regression: the shared `FindBraceRange` `'` heuristic previously assumed a char
        // literal (closing `'` within ~12 chars) and silently skipped only the opening `'`
        // if none was found nearby. In PHP `'...'` is a full string literal, so a long
        // default argument such as `$x = 'aaaaaaaaaaaaaaa['` leaked the `[` into the shared
        // paren / bracket depth counters — `parenDepth` stayed > 0 at the real body `{`, so
        // `demo` ended up with null body range and `callThing()` lost its container. Now
        // the scanner treats `'...'` as a full string literal for PHP specifically.
        // PHP の `'...'` を char literal として扱うと長い文字列内の `[` / `{` で body 範囲が崩れる。
        const string content = """
            <?php
            function demo($x = 'aaaaaaaaaaaaaaa[') { return callThing(); }
            """;

        var symbols = SymbolExtractor.Extract(1, "php", content);
        var references = ReferenceExtractor.Extract(1, "php", content, symbols);

        var demo = Assert.Single(symbols, s => s.Name == "demo" && s.Kind == "function");
        Assert.NotNull(demo.BodyStartLine);
        Assert.NotNull(demo.BodyEndLine);

        Assert.Contains(references, r =>
            r.SymbolName == "callThing" && r.ReferenceKind == "call"
            && r.ContainerKind == "function" && r.ContainerName == "demo");
    }

    [Fact]
    public void Extract_CSharpPrimaryCtor_SameLineAttributeCallsStayOnClassContainer()
    {
        // Regression: the synthetic C# primary-ctor container previously applied to every
        // call on the declaration's start line, including attribute argument calls that
        // textually precede the `class` keyword. `[Attr(Helper.Get())] public class Child(int x) : Parent(x) {}`
        // then attributed `Attr` and `Get` to the synthetic `function:Child` container, so
        // `callers Attr` / `callers Helper.Get` looked like the child ctor called them.
        // The synthetic range now tracks a start column at the `class` keyword, so tokens
        // before it stay on the real `class:Child` container while `Parent(x)` remains on
        // the synthetic ctor.
        // 宣言行より前の属性呼び出しが合成 primary-ctor コンテナに奪われないことを固定する。
        const string content =
            "[Attr(Helper.Get())] public class Child(int x) : Parent(x) {}\n";

        var symbols = SymbolExtractor.Extract(1, "csharp", content);
        var references = ReferenceExtractor.Extract(1, "csharp", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "Attr" && r.ContainerKind == "class" && r.ContainerName == "Child");
        Assert.Contains(references, r =>
            r.SymbolName == "Get" && r.ContainerKind == "class" && r.ContainerName == "Child");
        Assert.Contains(references, r =>
            r.SymbolName == "Parent" && r.ContainerKind == "function" && r.ContainerName == "Child");

        // No `Attr` / `Get` references should be attributed to the synthetic function ctor.
        Assert.DoesNotContain(references, r =>
            (r.SymbolName == "Attr" || r.SymbolName == "Get")
            && r.ContainerKind == "function" && r.ContainerName == "Child");
    }

    [Fact]
    public void TryExtractJavaCtorNameFromLine_QuotedAnnotationArg_ReturnsCtorName()
    {
        // Direct regression on the shared annotation scanner: an `)` inside a string literal
        // argument must not end the balanced-paren walk, otherwise ctor name extraction lands
        // on the `"` and returns null.
        // annotation 引数の文字列リテラル内の `)` で走査が切れないことを直接検証。
        Assert.Equal(
            "Leaf",
            ReferenceExtractor.TryExtractJavaCtorNameFromLine("public @Ann(text=\")\") Leaf(){super(0);}"));
        Assert.Equal(
            "Leaf",
            ReferenceExtractor.TryExtractJavaCtorNameFromLine("@Ann(text=\"(\") Leaf(){this(0);}"));
    }

    [Fact]
    public void Extract_Java_SameLineCtorBodyCall_AttributesToCtorContainer()
    {
        // Regression: non-chain body calls on a same-line Java ctor (for example the
        // `Helper.doWork()` statement after `super(0);` in `Leaf(T x){super(0); Helper.doWork();}`)
        // previously landed on `class:Leaf` because SymbolExtractor does not emit a function
        // symbol for the same-line ctor shape. The main loop now pre-computes a per-line synthetic
        // function-kind container covering the body `{ ... }` span so body calls attribute to
        // `function:Leaf` instead of leaking to the enclosing class.
        // 同一行 ctor 本体の通常 call が外側 class に吸われず、合成 function コンテナに帰属することを固定する。
        const string content = """
            package demo;

            class Helper {
                static void doWork() {}
            }

            class Root {
                Root(int v) {}
            }

            class Leaf extends Root {
                public <T> Leaf(T x){super(0); Helper.doWork();}
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.Contains(references, r =>
            r.SymbolName == "doWork" && r.ReferenceKind == "call"
            && r.ContainerKind == "function" && r.ContainerName == "Leaf");
        Assert.DoesNotContain(references, r =>
            r.SymbolName == "doWork" && r.ContainerKind == "class");

        // Chain edge remains on the synthetic function ctor too.
        // 連鎖エッジも合成 function コンテナに帰属したままであることを確認する。
        Assert.Contains(references, r =>
            r.SymbolName == "Root" && r.ReferenceKind == "call"
            && r.ContainerKind == "function" && r.ContainerName == "Leaf");
    }

    [Fact]
    public void Extract_Java_SameLineCtorDeclarator_DoesNotEmitSelfCall()
    {
        // Regression: `CallRegex` matches `CtorName(` on the declarator of a same-line Java ctor
        // and, without suppression, emitted a phantom `Leaf|call|class|Leaf` edge attributing the
        // declarator to the enclosing class. The main loop now skips the `CtorName(` match at the
        // declarator's name column when the current line carries a synthesized same-line ctor.
        // 同一行 ctor の宣言子 `CtorName(` が自己 call として記録されないことを固定する。
        const string content = """
            package demo;

            class Root {
                Root(int v) {}
            }

            class Leaf extends Root {
                Leaf(){super(0);}
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.DoesNotContain(references, r =>
            r.SymbolName == "Leaf" && r.ReferenceKind == "call");
        // But the chain rewrite still emits the `Root` edge attributed to `function:Leaf`.
        // 連鎖書き換えによる `Root` エッジは残っていることを確認する。
        Assert.Contains(references, r =>
            r.SymbolName == "Root" && r.ReferenceKind == "call"
            && r.ContainerKind == "function" && r.ContainerName == "Leaf");
    }

    [Fact]
    public void Extract_Java_ModuleInfoDirectives_EmitModuleDependencyReferences()
    {
        // JPMS directives are dependency edges, not calls. `requires`, `uses`, and
        // `provides ... with ...` should all surface as `type_reference` rows so graph
        // queries can answer module-level dependency questions.
        // JPMS の directive は call ではなく dependency edge であり、`requires` / `uses` /
        // `provides ... with ...` が `type_reference` として見える必要がある。
        const string content = """
            module com.example.app {
                requires java.base;
                requires transitive java.logging;
                uses com.example.spi.MyService;
                provides com.example.spi.MyService with com.example.impl.DefaultService;
            }
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.Equal(5, references.Count);
        Assert.All(references, reference => Assert.Equal("type_reference", reference.ReferenceKind));
        Assert.All(references, reference => Assert.Equal("com.example.app", reference.ContainerName));
        Assert.Contains(references, reference =>
            reference.SymbolName == "java.base"
            && reference.ContainerKind == "namespace");
        Assert.Contains(references, reference =>
            reference.SymbolName == "java.logging"
            && reference.ContainerKind == "namespace");
        Assert.Equal(2, references.Count(reference => reference.SymbolName == "com.example.spi.MyService"));
        Assert.Single(references, reference =>
            reference.SymbolName == "com.example.impl.DefaultService");
    }

    [Fact]
    public void Extract_Java_SealedPermitsList_EmitsTypeReferences()
    {
        const string content = """
            sealed interface Shape permits Circle, Square {}
            final class Circle implements Shape {}
            non-sealed class Square implements Shape {}
            """;

        var symbols = SymbolExtractor.Extract(1, "java", content);
        var references = ReferenceExtractor.Extract(1, "java", content, symbols);

        Assert.Contains(references, reference =>
            reference.SymbolName == "Circle"
            && reference.ReferenceKind == "type_reference"
            && reference.Context.StartsWith("sealed interface Shape permits", StringComparison.Ordinal));
        Assert.Contains(references, reference =>
            reference.SymbolName == "Square"
            && reference.ReferenceKind == "type_reference"
            && reference.Context.StartsWith("sealed interface Shape permits", StringComparison.Ordinal));
    }

    [Fact]
    public void Extract_SqlExecNoParens_CapturesStoredProcedureCall()
    {
        // issue #232: T-SQL `EXEC <proc>;` (no parentheses) is the dominant stored-procedure
        // call form. CallRegex requires a trailing `(`, so without SqlProcCallRegex the
        // reference graph misses every `EXEC`/`EXECUTE`/`CALL` site that does not use parens.
        // issue #232: T-SQL の `EXEC <proc>;` (括弧なし) がストアド呼び出しの主要形。
        const string content = """
            EXEC dbo.sp_Target;
            EXECUTE sp_Target;
            EXEC dbo.sp_Target @x = 1, @y = 2;
            EXEC dbo.sp_Target 1, 2;
            EXEC dbo.sp_Target();
            EXEC [dbo].[sp_Target];
            CALL sp_Target();
            CALL sp_Target;
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        var targetRefs = references.Where(r => r.SymbolName == "sp_Target").ToList();
        Assert.Equal(8, targetRefs.Count);
        Assert.All(targetRefs, r => Assert.Equal("call", r.ReferenceKind));
    }

    [Fact]
    public void Extract_SqlExecWithReturnAssignment_CapturesStoredProcedureCall()
    {
        // T-SQL return-value assignment: `EXEC @retval = dbo.sp_Target ...`. The call target
        // is still `sp_Target`, not `@retval`.
        // T-SQL の戻り値代入形式。呼び出し対象はあくまで `sp_Target`。
        const string content = """
            DECLARE @r int;
            EXEC @r = dbo.sp_Target @x = 1;
            EXECUTE @r = sp_Target;
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        var targetRefs = references.Where(r => r.SymbolName == "sp_Target").ToList();
        Assert.Equal(2, targetRefs.Count);
        Assert.All(targetRefs, r => Assert.Equal("call", r.ReferenceKind));
    }

    [Fact]
    public void Extract_SqlExecuteAs_NotExtractedAsReference()
    {
        // `EXECUTE AS '<user>'` is a context switch, not a stored-procedure call. `AS` must not
        // leak into the reference graph as `call AS`. Same for lowercase `as`.
        // `EXECUTE AS` はコンテキスト切替でありプロシージャ呼び出しではない。大文字小文字どちらでも参照化しない。
        const string content = """
            EXECUTE AS 'dbo';
            execute as user = 'admin';
            EXECUTE IMMEDIATE 'SELECT 1';
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        Assert.DoesNotContain(references, r => r.SymbolName.Equals("AS", StringComparison.OrdinalIgnoreCase));
        Assert.DoesNotContain(references, r => r.SymbolName.Equals("IMMEDIATE", StringComparison.OrdinalIgnoreCase));
    }

    [Fact]
    public void Extract_SqlExecInsideStringLiteral_NotExtractedAsReference()
    {
        // `EXEC` text inside a SQL string literal must not produce a reference — the literal is
        // dynamic SQL stored as data, not a call site.
        // SQL 文字列リテラル内の `EXEC` は動的 SQL の中身であり呼び出し箇所ではない。
        const string content = """
            DECLARE @sql nvarchar(max) = 'EXEC dbo.sp_InsideString;';
            EXEC sp_executesql @sql;
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        Assert.DoesNotContain(references, r => r.SymbolName == "sp_InsideString");
        // The outer EXEC of sp_executesql still becomes a reference.
        // 外側の EXEC による sp_executesql の参照は残る。
        Assert.Contains(references, r => r.SymbolName == "sp_executesql" && r.ReferenceKind == "call");
    }

    [Fact]
    public void Extract_SqlExecCallDedup_DoesNotEmitDuplicateForParenForm()
    {
        // When a call already has a trailing `(`, the shared CallRegex and SqlProcCallRegex both
        // match the same name at the same column. Dedup must collapse them into one reference row.
        // `(` 付きの形は CallRegex と SqlProcCallRegex の両方がヒットするが、dedup で 1 件に収まる。
        const string content = """
            EXEC dbo.sp_Target();
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        var targetRefs = references.Where(r => r.SymbolName == "sp_Target").ToList();
        Assert.Single(targetRefs);
    }

    [Fact]
    public void Extract_SqlQualifiedDefinition_DoesNotEmitPhantomSelfReference()
    {
        // Schema-qualified SQL symbols keep their qualified definition name (`dbo.fn_X`), while
        // CallRegex only captures the leaf call token (`fn_X`). The definition-line suppression
        // must therefore compare both the full and leaf forms so the header is not misindexed as
        // a self-call. Issue #296.
        // SQL の定義名は `dbo.fn_X` のように修飾付きだが、CallRegex は leaf の `fn_X` だけを拾う。
        // そのため定義行の自己呼び出し抑止は full/leaf の両方を比較し、ヘッダを幽霊 call にしない必要がある。
        const string content = """
            CREATE FUNCTION dbo.fn_GetOrderItems(@orderId INT)
            RETURNS TABLE
            AS
            RETURN (SELECT * FROM dbo.OrderItems WHERE OrderId = @orderId);
            GO

            CREATE PROCEDURE dbo.usp_GetOrders
            AS
            BEGIN
                SELECT *
                FROM dbo.Orders o
                CROSS APPLY dbo.fn_GetOrderItems(o.OrderId) fi;
            END
            GO
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        var targetRefs = references
            .Where(r => r.SymbolName == "fn_GetOrderItems" && r.ReferenceKind == "call")
            .ToList();

        var realCall = Assert.Single(targetRefs);
        Assert.Equal(12, realCall.Line);
        Assert.Equal("dbo.usp_GetOrders", realCall.ContainerName);
    }

    [Fact]
    public void Extract_SqlQualifiedDefinition_SameLineCrossSchemaCallStillEmitsReference()
    {
        const string content = """
            CREATE PROCEDURE sales.fn_Target AS EXEC dbo.fn_Target;
            GO
            """;

        var symbols = SymbolExtractor.Extract(1, "sql", content);
        var references = ReferenceExtractor.Extract(1, "sql", content, symbols);

        var targetRef = Assert.Single(references.Where(r => r.SymbolName == "fn_Target" && r.ReferenceKind == "call"));
        Assert.Equal(1, targetRef.Line);
        Assert.Equal("sales.fn_Target", targetRef.ContainerName);
    }

    [Fact]
    public void Extract_SqlQualifiedDefinition_SameLineCallAfterStringLiteralPreservesRawColumn()
    {
        const string content = """
            CREATE PROCEDURE sales.host
            AS
