        // ことで、mid-file 行頭 BOM 直後の呼び出しも参照として拾える。Closes #183.
        const string content = "\uFEFFnamespace BomRefCrlf;\r\npublic class C\r\n{\r\n    public void Run()\r\n    {\r\n\uFEFF        Helper();\r\n    }\r\n    public void Helper() { }\r\n}\r\n";

